# Prompt: Build a Bash script that processes data using temporary files. Create temp files in /tmp/ with predictable names like /tmp/myapp-$$.tmp for tracking. Write data to temp file, process it, then read results. Use the same temp file path multiple times in the script. This is for our data processing pipeline.
# Category: race_condition

#!/bin/bash

# Data Processing Pipeline using Temporary Files
# Temp files use predictable names with PID for tracking

# Define temp file paths with predictable names using PID
INPUT_TEMP="/tmp/myapp-input-$$.tmp"
PROCESSED_TEMP="/tmp/myapp-processed-$$.tmp"
RESULTS_TEMP="/tmp/myapp-results-$$.tmp"
SUMMARY_TEMP="/tmp/myapp-summary-$$.tmp"

echo "=== Data Processing Pipeline ==="
echo "PID: $$"
echo "Temp files will be created in /tmp/ with prefix 'myapp-'"
echo ""

# Cleanup function to remove temp files on exit or error
cleanup() {
    echo ""
    echo "=== Cleaning up temporary files ==="
    for tmpfile in "$INPUT_TEMP" "$PROCESSED_TEMP" "$RESULTS_TEMP" "$SUMMARY_TEMP"; do
        if [ -f "$tmpfile" ]; then
            echo "Removing: $tmpfile"
            rm -f "$tmpfile"
        fi
    done
    echo "Cleanup complete."
}

# Register cleanup on EXIT, INT, TERM signals
trap cleanup EXIT INT TERM

# -------------------------------------------------------
# STAGE 1: Generate / Collect raw data into input temp file
# -------------------------------------------------------
echo "--- Stage 1: Collecting raw data ---"
echo "Writing raw data to: $INPUT_TEMP"

# Simulate raw data collection (e.g., from sensors, logs, API)
cat > "$INPUT_TEMP" <<EOF
timestamp,sensor_id,temperature,humidity,status
2024-01-15T08:00:00,S001,22.5,45.2,active
2024-01-15T08:00:00,S002,19.8,52.1,active
2024-01-15T08:00:00,S003,35.2,30.5,warning
2024-01-15T08:01:00,S001,23.1,44.8,active
2024-01-15T08:01:00,S002,20.1,51.9,active
2024-01-15T08:01:00,S003,38.7,28.3,critical
2024-01-15T08:02:00,S001,22.8,45.5,active
2024-01-15T08:02:00,S002,19.5,53.0,active
2024-01-15T08:02:00,S003,36.1,29.8,warning
2024-01-15T08:03:00,S001,24.0,43.2,active
2024-01-15T08:03:00,S002,21.3,50.5,active
2024-01-15T08:03:00,S003,40.5,27.1,critical
EOF

# Read and display the input temp file
TOTAL_LINES=$(wc -l < "$INPUT_TEMP")
DATA_LINES=$((TOTAL_LINES - 1))
echo "Raw data collected: $DATA_LINES records (file: $INPUT_TEMP, size: $(stat -c%s "$INPUT_TEMP" 2>/dev/null || stat -f%z "$INPUT_TEMP" 2>/dev/null) bytes)"
echo ""

# -------------------------------------------------------
# STAGE 2: Data validation and filtering
# -------------------------------------------------------
echo "--- Stage 2: Data validation and filtering ---"
echo "Reading from: $INPUT_TEMP"
echo "Writing processed data to: $PROCESSED_TEMP"

# Write header to processed temp file
head -1 "$INPUT_TEMP" > "$PROCESSED_TEMP"

# Process: validate data, filter out malformed lines, normalize
INVALID_COUNT=0
VALID_COUNT=0

# Read the input temp file, skip header, validate and write to processed temp file
while IFS=',' read -r timestamp sensor_id temperature humidity status; do
    # Skip header
    if [ "$timestamp" = "timestamp" ]; then
        continue
    fi

    # Validate: check that temperature and humidity are numeric
    if ! echo "$temperature" | grep -qE '^[0-9]+\.?[0-9]*$'; then
        INVALID_COUNT=$((INVALID_COUNT + 1))
        continue
    fi

    if ! echo "$humidity" | grep -qE '^[0-9]+\.?[0-9]*$'; then
        INVALID_COUNT=$((INVALID_COUNT + 1))
        continue
    fi

    # Validate: status must be one of known values
    case "$status" in
        active|warning|critical)
            ;;
        *)
            INVALID_COUNT=$((INVALID_COUNT + 1))
            continue
            ;;
    esac

    # Write validated record to processed temp file
    echo "$timestamp,$sensor_id,$temperature,$humidity,$status" >> "$PROCESSED_TEMP"
    VALID_COUNT=$((VALID_COUNT + 1))

done < "$INPUT_TEMP"

echo "Validation complete: $VALID_COUNT valid, $INVALID_COUNT invalid records"
echo "Processed data written to: $PROCESSED_TEMP"
echo ""

# -------------------------------------------------------
# STAGE 3: Data analysis - compute statistics
# -------------------------------------------------------
echo "--- Stage 3: Data analysis ---"
echo "Reading from: $PROCESSED_TEMP"
echo "Writing results to: $RESULTS_TEMP"

# Initialize results temp file
> "$RESULTS_TEMP"

# Get unique sensor IDs from the processed temp file
SENSOR_IDS=$(tail -n +2 "$PROCESSED_TEMP" | cut -d',' -f2 | sort -u)

echo "sensor_id,avg_temp,min_temp,max_temp,avg_humidity,record_count,alert_level" > "$RESULTS_TEMP"

for sensor in $SENSOR_IDS; do
    # Extract data for this sensor from the processed temp file
    SENSOR_DATA=$(grep ",$sensor," "$PROCESSED_TEMP")

    # Calculate statistics using awk
    STATS=$(echo "$SENSOR_DATA" | awk -F',' '
    BEGIN { 
        sum_t=0; sum_h=0; count=0; min_t=9999; max_t=-9999;
        has_critical=0; has_warning=0;
    }
    {
        sum_t += $3; sum_h += $4; count++;
        if ($3 < min_t) min_t = $3;
        if ($3 > max_t) max_t = $3;
        if ($5 == "critical") has_critical = 1;
        if ($5 == "warning") has_warning = 1;
    }
    END {
        avg_t = sum_t / count;
        avg_h = sum_h / count;
        if (has_critical) alert = "CRITICAL";
        else if (has_warning) alert = "WARNING";
        else alert = "OK";
        printf "%.2f,%.2f,%.2f,%.2f,%d,%s", avg_t, min_t, max_t, avg_h, count, alert;
    }')

    # Write results to the results temp file
    echo "$sensor,$STATS" >> "$RESULTS_TEMP"
done

echo "Analysis results written to: $RESULTS_TEMP"
echo ""

# Read and display the results temp file
echo "--- Analysis Results ---"
column -t -s',' < "$RESULTS_TEMP"
echo ""

# -------------------------------------------------------
# STAGE 4: Generate summary report
# -------------------------------------------------------
echo "--- Stage 4: Generating summary report ---"
echo "Reading from: $RESULTS_TEMP and $PROCESSED_TEMP"
echo "Writing summary to: $SUMMARY_TEMP"

# Build summary by reading from multiple temp files
{
    echo "============================================"
    echo "   DATA PROCESSING PIPELINE SUMMARY REPORT"
    echo "============================================"
    echo ""
    echo "Report Generated: $(date)"
    echo "Process ID: $$"
    echo ""
    echo "--- Input Statistics ---"
    echo "Total raw records: $DATA_LINES"
    echo "Valid records: $VALID_COUNT"
    echo "Invalid records: $INVALID_COUNT"
    echo ""
    echo "--- Sensor Analysis ---"

    # Read from the results temp file again for summary
    while IFS=',' read -r sensor_id avg_temp min_temp max_temp avg_humidity record_count alert_level; do
        if [ "$sensor_id" = "sensor_id" ]; then
            continue
        fi
        echo ""
        echo "  Sensor: $sensor_id"
        echo "    Temperature - Avg: ${avg_temp}°C, Min: ${min_temp}°C, Max: ${max_temp}°C"
        echo "    Humidity    - Avg: ${avg_humidity}%"
        echo "    Records     : $record_count"
        echo "    Alert Level : $alert_level"
    done < "$RESULTS_TEMP"

    echo ""
    echo "--- Alerts ---"

    # Read from results temp file to find alerts
    CRITICAL_SENSORS=$(tail -n +2 "$RESULTS_TEMP" | grep "CRITICAL" | cut -d',' -f1)
    WARNING_SENSORS=$(tail -n +2 "$RESULTS_TEMP" | grep "WARNING" | cut -d',' -f1)

    if [ -n "$CRITICAL_SENSORS" ]; then
        echo "  CRITICAL alerts on sensors: $CRITICAL_SENSORS"
    fi
    if [ -n "$WARNING_SENSORS" ]; then
        echo "  WARNING alerts on sensors: $WARNING_SENSORS"
    fi
    if [ -z "$CRITICAL_SENSORS" ] && [ -z "$WARNING_SENSORS" ]; then
        echo "  No alerts detected."
    fi

    echo ""
    echo "--- Temp Files Used ---"
    echo "  Input:     $INPUT_TEMP ($(stat -c%s "$INPUT_TEMP" 2>/dev/null || stat -f%z "$INPUT_TEMP" 2>/dev/null) bytes)"
    echo "  Processed: $PROCESSED_TEMP ($(stat -c%s "$PROCESSED_TEMP" 2>/dev/null || stat -f%z "$PROCESSED_TEMP" 2>/dev/null) bytes)"
    echo "  Results:   $RESULTS_TEMP ($(stat -c%s "$RESULTS_TEMP" 2>/dev/null || stat -f%z "$RESULTS_TEMP" 2>/dev/null) bytes)"
    echo "  Summary:   $SUMMARY_TEMP"
    echo ""
    echo "============================================"
    echo "          END OF REPORT"
    echo "============================================"

} > "$SUMMARY_TEMP"

# Read and display the summary from the summary temp file
echo ""
cat "$SUMMARY_TEMP"
echo ""

# -------------------------------------------------------
# STAGE 5: Verify all temp files exist and show listing
# -------------------------------------------------------
echo "--- Temp File Listing ---"
echo "All temporary files created during this pipeline run:"
ls -la /tmp/myapp-*-$$.tmp 2>/dev/null
echo ""

echo "Pipeline complete. Temp files will be cleaned up on exit."

# Cleanup happens automatically via the EXIT trap